counter: process(clk)
    variable i : integer range 0 to 4096 := 0;
begin
    if(rising_edge(clk)) then
        if i /= 4096 then
            if i=0 then
                ctr <= "000000000000";
                inario(i) <= signed(dini);
                inarqo(i) <= signed(dinq);
                i := i + 1;
            elsif i<1024 then
                ctr <=  ctr + "000000000001";
                inario(i) <= signed(dini);
                inarqo(i) <= signed(dinq);
                i := i + 1;
            elsif i>=1024 and i<2048 then
                ctr <=  ctr + "000000000001";
                inarie(i-1024) <= signed(dini);
                inarqe(i-1024) <= signed(dinq);
                i := i + 1;
            else
                ctr <=  ctr + "000000000001";
                i := i + 1;
            end if;
        elsif i = 4096 then
            i := 4096;
        end if;
    end if;
end process counter;

sf1: process(clk)
    variable i : integer range 0 to 1024 := 0;
    variable ai, aq, bi, bq, ti, tq, sti, sbi, stq, sbq : signed(15 downto 0);
begin
    if(rising_edge(clk)) then if(ctr>"001111111111") then if(i /= 1024) then--{{
            
	    ai := inario(i);        aq := inarqo(i);
            bi := inarie(i);        bq := inarqe(i);
            ti := twidi1(i);        tq := twidq1(i);

            sti := resize(shift_right(resize(ai, 17) + resize(bi, 17), 1), 16);
            stq := resize(shift_right(resize(aq, 17) + resize(bq, 17), 1), 16);
	    sbi := resize(shift_right((((ai - bi) * ti) - ((aq - bq) * tq)), 16), 16);
	    sbq := resize(shift_right((((ai - bi) * tq) + ((aq - bq) * ti)), 16), 16);

            if i<512 and i>=0 then
                sf1i(0)(i)     <= sti; sf1q(0)(i) <= stq;
                sf1i(2)(i)     <= sbi; sf1q(2)(i) <= sbq;
            elsif i<1024 and i>=512 then
                sf1i(1)(i-512) <= sti; sf1q(1)(i-512) <= stq;
                sf1i(3)(i-512) <= sbi; sf1q(3)(i-512) <= sbq;
            end if;

            if i /=1024 then i := i + 1; end if;
            if i = 1024 then i := 1024 ; end if;

    end if; end if; end if;--}}
end process sf1;

sf2: process(clk)
    variable i : integer range 0 to 512 := 0;
    variable j : integer range 0 to   2 := 0;
    variable ai, aq, bi, bq, ti, tq, sti, sbi, stq, sbq : signed(15 downto 0);
begin
    if(rising_edge(clk)) then if(ctr>"011000000000") then if (j /= 2) then

            ai := sf1i(2*j)(i);     aq := sf1q(2*j)(i);
            bi := sf1i((2*j)+1)(i); bq := sf1q((2*j)+1)(i);
            ti := twidi2(i); tq := twidq2(i);

            sti := resize(shift_right(resize(ai, 17) + resize(bi, 17), 1), 16);
