                sf2i((4*j)+3)(i-256) <= sbi; sf2q((4*j)+3)(i-256) <= sbq;
            end if;

            if j /=2 then i := i + 1; end if;
            if i = 512 then if j /=2 then i:=0; j:=j+1; end if; end if;
            if j = 2 then j:=2; end if;

    end if; end if; end if;--}}
end process sf2;

