begin
    if(rising_edge(clk)) then if(ctr>"011111110000") then if (j /= 64) then

            ai := sf6i(2*j)(i);     aq := sf6q(2*j)(i);
            bi := sf6i((2*j)+1)(i); bq := sf6q((2*j)+1)(i);
            ti := twidi7(i); tq := twidq7(i);

