sf8: process(clk)
    variable i : integer range 0 to  8 := 0;
    variable j : integer range 0 to  128 := 0;
    variable ai, aq, bi, bq, ti, tq, sti, sbi, stq, sbq : signed(15 downto 0);
begin
    if(rising_edge(clk)) then if(ctr>"011111111000") then if (j /= 128) then

            ai := sf7i(2*j)(i);     aq := sf7q(2*j)(i);
