    --constant rom_i : rom_type := (
  --      others => x"7FFF"
--    );
    constant rom_q : rom_type := (
        others => x"0000"
    );

begin

    -- Instantiate the Unit Under Test (UUT)
    uut: test4fftmul port map (
        clk   => clk,
        dini  => dini,
        dinq  => dinq,
        doui  => doui,
        douq  => douq,
        doval => doval          -- <-- connected
    );

    -- Clock process
    clk_process : process
    begin
        clk <= '0';
        wait for clk_period/2;
        clk <= '1';
        wait for clk_period/2;
    end process;

    -- Stimulus process (unchanged)
    stim_proc: process
    begin
        for i in 0 to 2047 loop
            dini <= std_logic_vector(rom_i(i));
            dinq <= std_logic_vector(rom_q(i));
            wait until rising_edge(clk);
        end loop;
        dini <= (others => '0');
        dinq <= (others => '0');
        wait;   -- let the FFT finish (will be stopped by capture process)
    end process;

    -- ========== CAPTURE AND FILE WRITE ==========
    capture_and_write: process
        file outfile     : text open write_mode is "fft_output.txt";
        variable buf     : line;
        variable idx     : integer := 0;
        variable first   : boolean;
        type capture_t is array (0 to 2047) of integer;
        variable cap_i   : capture_t;
        variable cap_q   : capture_t;
    begin
        -- Wait for first valid output
        wait until rising_edge(clk) and doval = '1';

        -- Capture 2048 I and Q values
        for idx in 0 to 2047 loop
            cap_i(idx) := to_integer(signed(doui));
            cap_q(idx) := to_integer(signed(douq));
            if idx < 2047 then
                wait until rising_edge(clk) and doval = '1';
            end if;
        end loop;

        -- Write I array
        write(buf, string'("fi = ["));
        first := true;
        for idx in 0 to 2047 loop
            if not first then
                write(buf, string'(","));
            end if;
            first := false;
            write(buf, cap_i(idx));
        end loop;
        write(buf, string'("];"));
        writeline(outfile, buf);

        -- Write Q array
        write(buf, string'("fq = ["));
        first := true;
        for idx in 0 to 2047 loop
            if not first then
                write(buf, string'(","));
            end if;
            first := false;
            write(buf, cap_q(idx));
        end loop;
        write(buf, string'("];"));
        writeline(outfile, buf);

        file_close(outfile);
        report "FFT output written to fft_output.txt" severity note;
        report "Simulation finished successfully" severity failure;
        wait;
    end process;
    -- ============================================

end behavior;
